module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

    wire [32:0] C;

    // First stage CLA
    wire [15:0] S1;
    wire C16;
    assign {C16, S1} = A[16:1] + B[16:1];

    // Second stage CLA
    wire [15:0] S2;
    assign {C32, S2} = A[32:17] + B[32:17] + C16;

    // Combine the results
    assign S = {S2, S1};

endmodule
